    RNMCNO, EVAL_DT, RA_GRD, RA_SCR, EDD_F, NEXT_EVAL_DT, REMARK, REG_ID, REG_DT
) VALUES (
    #{custNo}, #{evalDt}, #{raGrd}, #{raScr}, #{eddYn}, #{nextEvalDt}, #{remark}, #{regId}, CURRENT_TIMESTAMP
)

INSERT INTO RA_RESULT (
    RNMCNO, EVAL_DT, RA_GRD, RA_SCR, EDD_F, NEXT_EVAL_DT, REMARK, REG_ID, REG_DT
) VALUES (
    #{custNo}, #{evalDt}, #{raGrd}, #{raScr}, #{eddYn}, #{nextEvalDt}, #{remark}, #{regId}, SYSDATE
)

mapper.select:
SELECT RA_ID, RNMCNO, EVAL_DT, RA_GRD, RA_SCR, EDD_F, NEXT_EVAL_DT,
       REMARK, REG_ID, REG_DT, UPD_ID, UPD_DT
FROM RA_RESULT
WHERE 1=1

    AND RNMCNO = #{custNo}


    AND RA_GRD = #{raGrd}


    AND EDD_F = #{eddYn}

ORDER BY REG_DT DESC
LIMIT #{size} OFFSET #{offset}

SELECT * FROM (
    SELECT ROWNUM AS RN, T.* FROM (
        SELECT RA_ID, RNMCNO, EVAL_DT, RA_GRD, RA_SCR, EDD_F, NEXT_EVAL_DT,
               REMARK, REG_ID, REG_DT, UPD_ID, UPD_DT
        FROM RA_RESULT
        WHERE 1=1

            AND RNMCNO = #{custNo}


            AND RA_GRD = #{raGrd}


            AND EDD_F = #{eddYn}

        ORDER BY REG_DT DESC
    ) T WHERE ROWNUM <= #{offset} + #{size}
) WHERE RN > #{offset}

SELECT COUNT(*)
FROM RA_RESULT
WHERE 1=1

    AND RNMCNO = #{custNo}


    AND RA_GRD = #{raGrd}


    AND EDD_F = #{eddYn}
